#!/usr/bin/env python
"""Verify that the collections ABC migration is complete."""

import os
import re
from pathlib import Path

def check_collections_imports(repo_root):
    """Check for proper collections ABC imports."""
    issues = []

    # Directories to check
    check_dirs = [
        'lib/ansible/modules',
        'lib/ansible/module_utils',
        'lib/ansible/plugins',
        'lib/ansible/cli',
        'lib/ansible/executor',
        'lib/ansible/inventory',
        'lib/ansible/parsing',
        'lib/ansible/playbook',
    ]

    for check_dir in check_dirs:
        dir_path = Path(repo_root) / check_dir
        if not dir_path.exists():
            continue

        for py_file in dir_path.rglob('*.py'):
            if '__pycache__' in str(py_file):
                continue
            if '_collections_compat.py' in str(py_file):
                continue

            try:
                content = py_file.read_text()
            except Exception as e:
                continue

            # Check for imports from _collections_compat
            if '_collections_compat' in content:
                issues.append(f"❌ {py_file.relative_to(repo_root)}: imports from _collections_compat")

            # Check for incorrect collections imports of ABCs
            abc_pattern = r'from collections import.*(?:Mapping|Sequence|Iterable|Set|Container|Hashable|Callable|Sized|MutableMapping|MutableSequence|MutableSet|ItemsView|KeysView|ValuesView|MappingView)'
            if re.search(abc_pattern, content):
                issues.append(f"❌ {py_file.relative_to(repo_root)}: imports ABCs from collections instead of collections.abc")

    return issues

def check_sanity_config(repo_root):
    """Check that sanity checks are properly configured."""
    issues = []

    unwanted_file = Path(repo_root) / 'test/lib/ansible_test/_util/controller/sanity/pylint/plugins/unwanted.py'

    if unwanted_file.exists():
        content = unwanted_file.read_text()

        # Check that collections module is listed as unwanted
        if "'collections'" not in content:
            issues.append("❌ 'collections' module not listed in unwanted imports")
        else:
            # Check that it mentions the ABC imports
            if 'Mapping' not in content or 'Sequence' not in content:
                issues.append("❌ Sanity check not configured for ABC imports from collections")

        # Check that _collections_compat is NOT recommended as alternative
        if '_collections_compat' in content:
            issues.append("❌ _collections_compat should not be mentioned in unwanted imports")

    return issues

if __name__ == '__main__':
    repo_root = '/workspace'

    print("=" * 60)
    print("Collections ABC Migration Verification")
    print("=" * 60)
    print()

    print("1. Checking for improper imports in codebase...")
    code_issues = check_collections_imports(repo_root)
    if code_issues:
        print(f"   Found {len(code_issues)} issues:")
        for issue in code_issues:
            print(f"   {issue}")
    else:
        print("   ✅ No improper imports found")

    print()
    print("2. Checking sanity check configuration...")
    sanity_issues = check_sanity_config(repo_root)
    if sanity_issues:
        print(f"   Found {len(sanity_issues)} issues:")
        for issue in sanity_issues:
            print(f"   {issue}")
    else:
        print("   ✅ Sanity checks properly configured")

    print()
    print("3. Verifying deprecation shim is in place...")
    shim_file = Path(repo_root) / 'lib/ansible/module_utils/common/_collections_compat.py'
    if shim_file.exists():
        content = shim_file.read_text()
        if 'from collections.abc import' in content and '_warnings.deprecate' in content:
            print("   ✅ Shim is properly configured with deprecation warning")
        else:
            print("   ❌ Shim is not properly configured")
    else:
        print("   ❌ Shim file not found")

    print()
    all_issues = code_issues + sanity_issues
    if not all_issues:
        print("✅ Migration verification PASSED - All checks successful!")
    else:
        print(f"❌ Migration verification FAILED - {len(all_issues)} issues found")

    print("=" * 60)
